package day1;

public class Program8_ArithmeticOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int num1 =5, 	num2= 2;
		System.out.println(num1+num2);
		System.out.println(num1-num2);
		System.out.println(num1*num2);
		System.out.println(num1/num2);  // / is quotient
		System.out.println(num1%num2); // % getting devision(modulus=remainder)
		
		
		System.out.println(num2+1);
	}

}
